patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,6 +1,6 @@
 module magnitude_comparator_16bit(
   input [15:0] value_x, value_y,
   output reg gt, eq, lt
 );
-  always @(value_x) begin
+  always @(value_x or value_y) begin
     if (value_x > value_y) begin
       gt = 1'b1;
       eq = 1'b0;

before_code:
module magnitude_comparator_16bit(
  input [15:0] value_x, value_y,
  output reg gt, eq, lt
);
  always @(value_x) begin
    if (value_x > value_y) begin
      gt = 1'b1;
      eq = 1'b0;
      lt = 1'b0;
    end else if (value_x == value_y) begin
      gt = 1'b0;
      eq = 1'b1;
      lt = 1'b0;
    end else begin
      gt = 1'b0;
      eq = 1'b0;
      lt = 1'b1;
    end
  end
endmodule

after_code:
module magnitude_comparator_16bit(
  input [15:0] value_x, value_y,
  output reg gt, eq, lt
);
  always @(value_x or value_y) begin
    if (value_x > value_y) begin
      gt = 1'b1;
      eq = 1'b0;
      lt = 1'b0;
    end else if (value_x == value_y) begin
      gt = 1'b0;
      eq = 1'b1;
      lt = 1'b0;
    end else begin
      gt = 1'b0;
      eq = 1'b0;
      lt = 1'b1;
    end
  end
endmodule
